const express = require('express'); // Importing ExpressJS modules
const { Client } = require('@elastic/elasticsearch') // Importing Elasticsearch module
const app = express();
app.use(express.json())


const client = new Client({ node: 'http://localhost:9200' })

	client
		.search({ index:req.params.index, body:req.body.query })
		.then(({ body }) => {
			res.status(200).json(body) // response status 200
		})
	res.send(client.transport) // response status 503



// Creating GET route for the index, and querying Elasticsearch.
app.get('/es/:index', async function (req, res){
    try {
        const response = await client
            .search({
                index: req.params.index,
				// body: req.body // It will send the same query which was sent to ES. But this is unnecessary in this case.
            })

        if (!response) throw new Error('Search request not found') // 404 Error
        else res.send(JSON.stringify(response))
    } catch (error){
		// 503 Error
		console.log(error)
        res.sendStatus(503);
    };
});